// // This module selects between two sources: when the control input 'cu_aluScr' is low, it outputs 'extenderOutputA'; when high, it outputs 'data2'.
module top_module(data2, extenderOutputA, out, cu_aluScr);input cu_aluScr;
  input [31:0] data2;
  input [31:0] extenderOutputA;

  output reg [31:0] out;

  always @ ( * ) begin
    if(cu_aluScr)
      out = extenderOutputA;
    else
      out = data2;
  end
endmodule
